use crate::cmd::init::ShellIntegration;

pub fn emit_init_script(integration: ShellIntegration) {
    print!("{}", HEADER);
    match integration {
        ShellIntegration::False => {}
        ShellIntegration::True => print!("{}", SAFE_WRAPPER),
        ShellIntegration::Force => print!("{}", FORCE_WRAPPER),
    }
    print!("{}", COMPLETION);
}

const HEADER: &str = r#"
# git-mate shell integration — generated by `git-mate init zsh`
# Add this to your ~/.zshrc:
#   eval "$(command git-mate init zsh)"
"#;

const FORCE_WRAPPER: &str = r#"
# Auto-cd support
function git() {
    local _proto _exit
    _proto=$(mktemp) || return 1
    GIT_MATE_PROTO="$_proto" command git "$@"
    _exit=$?
    eval "$(command git-mate _protocol --zsh "$_proto")"
    rm -f "$_proto"
    return $_exit
}
"#;

const SAFE_WRAPPER: &str = r#"
# Auto-cd support
if [[ "$(type -w git 2>/dev/null)" == "git: function" ]]; then
    print "git-mate: warning: 'git' is already a shell function; skipping git() wrapper. Set mate.shellIntegration=force to override." >&2
else
    function git() {
        local _proto _exit
        _proto=$(mktemp) || return 1
        GIT_MATE_PROTO="$_proto" command git "$@"
        _exit=$?
        eval "$(command git-mate _protocol --zsh "$_proto")"
        rm -f "$_proto"
        return $_exit
    }
fi
"#;

const COMPLETION: &str = r#"
# Shell completions
source <(COMPLETE=zsh command git-mate)
"#;
